-- ============================================================
-- SECTION 2: STRUCTURE
-- ============================================================

DROP TABLE IF EXISTS public.student_profiles CASCADE;

CREATE TABLE public.student_profiles (
    id uuid NOT NULL DEFAULT gen_random_uuid(),
    user_id uuid,
    competences jsonb DEFAULT '{}'::jsonb,
    lacunes_identifiees jsonb DEFAULT '[]'::jsonb,
    style_apprentissage text,
    updated_at timestamp with time zone DEFAULT now(),
    recent_cours_context jsonb DEFAULT '{}'::jsonb,
    CONSTRAINT student_profiles_pkey PRIMARY KEY (id),
    CONSTRAINT student_profiles_user_id_key UNIQUE (user_id)
);

-- ============================================================
-- SECTION 3: FOREIGN KEYS
-- ============================================================
-- (Aucune foreign key pour cette table)

