-- CREATE UNIQUE INDEX student_profiles_user_id_key ON public.student_profiles USING btree (user_id);

-- ============================================================
-- SECTION 5: SECURITE RLS
-- ============================================================

ALTER TABLE public.student_profiles ENABLE ROW LEVEL SECURITY;

-- ============================================================
-- SECTION 6: POLICIES
-- ============================================================

CREATE POLICY "Parents can view their children's student profiles"
    ON public.student_profiles
    FOR SELECT
    TO public
    USING (
        EXISTS (
            SELECT 1 FROM parent_eleve_relations
            WHERE parent_eleve_relations.parent_user_id = auth.uid()
            AND parent_eleve_relations.eleve_user_id = student_profiles.user_id
        )
    );

CREATE POLICY "Users can delete their own student profile"
    ON public.student_profiles
    FOR DELETE
    TO public
    USING (auth.uid() = user_id);

CREATE POLICY "Users can insert their own student profile"
    ON public.student_profiles
    FOR INSERT
    TO public
    WITH CHECK (auth.uid() = user_id);

CREATE POLICY "Users can update their own student profile"
    ON public.student_profiles
    FOR UPDATE
    TO public
    USING (auth.uid() = user_id);

CREATE POLICY "Users can view their own student profile"
    ON public.student_profiles
    FOR SELECT
    TO public
    USING (auth.uid() = user_id);

-- ============================================================
-- SECTION 7: TRIGGERS
-- ============================================================

-- Fonction trigger (si elle n'existe pas déjà)
CREATE OR REPLACE FUNCTION public.update_updated_at_column()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = now();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = public;

CREATE TRIGGER update_student_profiles_updated_at
    BEFORE UPDATE ON public.student_profiles
    FOR EACH ROW
    EXECUTE FUNCTION public.update_updated_at_column();

